class Solution {
public:
    vector<int> smallestSubarrays(vector<int>& nums) {
        int n = nums.size();
        vector<int> res(n);
        for (int i = 0; i < n; i++) {
            int maxOr = 0, currOr = 0;
            for (int j = i; j < n; j++) {
                currOr |= nums[j];
                maxOr = max(maxOr, currOr);
            }
            for (int j = i, len = 1; j < n; j++, len++) {
                currOr = 0;
                for (int k = i; k <= j; k++) {
                    currOr |= nums[k];
                }
                if (currOr == maxOr) {
                    res[i] = len;
                    break;
                }
            }
        }
        return res;
    }
};
